666	    /// Cross-platform std.Io-backed server runtime.
667	    ///
668	    /// `std.Io.Threaded` is the first-party stdlib backend that currently
669	    /// supports the Unix-domain socket control plane zmux uses on both macOS
670	    /// and Linux, while the actual descriptor readiness loop remains the
671	    /// existing poll/tick dispatcher.
672	    pub fn run(self: *Server) !void {
673	        return self.runPoll();
674	    }
675	
676	    /// Cross-platform fd-readiness loop used by the std.Io-backed server runtime.
677	    fn runPoll(self: *Server) !void {
678	        const max_fds = 256;
679	        var pollfds: [max_fds]std.c.pollfd = undefined;
680	
681	        while (self.running) {
682	            self.drainAllClients();
683	            self.drainAllPanes();
684	            self.refreshStatusClientsIfDue();
685	            if (signals.SignalHandler.shouldExit()) {
686	                self.stop();
687	                break;
688	            }
689	
690	            var nfds: usize = 0;
691	            if (self.listen_fd >= 0) {
692	                pollfds[nfds] = .{ .fd = self.listen_fd, .events = POLLIN, .revents = 0 };
693	                nfds += 1;
694	            }
695	
696	            for (self.clients.items) |client| {
697	                if (nfds >= max_fds) break;
698	                pollfds[nfds] = .{ .fd = client.fd, .events = POLLIN, .revents = 0 };
699	                nfds += 1;
700	            }
701	
702	            for (self.sessions.items) |session| {
703	                for (session.windows.items) |window| {
704	                    for (window.panes.items) |pane| {
705	                        if (nfds >= max_fds) break;
706	                        if (pane.fd >= 0) {
707	                            pollfds[nfds] = .{ .fd = pane.fd, .events = POLLIN, .revents = 0 };
708	                            nfds += 1;
709	                        }
710	                    }
711	                }
712	            }
713	
714	            const result = std.c.poll(pollfds[0..nfds].ptr, @intCast(nfds), 100);
715	            if (result < 0) continue;
716	            if (result == 0) {
717	                startup_probe.traceEvent("server", "timer_tick", "source=poll");
718	                self.flushAllClientOutputs();
719	                self.drainAllClients();
720	                self.drainAllPanes();
721	                self.refreshStatusClientsIfDue();
722	                continue;
723	            }
724	
725	            if (nfds > 0 and pollfds[0].revents & POLLIN != 0) {
726	                self.acceptClient() catch {};
727	            }
728	
729	            var i: usize = if (self.listen_fd >= 0) 1 else 0;
730	            while (i < nfds) : (i += 1) {
731	                if (pollfds[i].revents & POLLIN == 0) continue;
732	                const fd = pollfds[i].fd;
733	                if (self.findClientIndex(fd)) |client_idx| {
734	                    var detail: [160]u8 = undefined;
735	                    const msg = std.fmt.bufPrint(&detail, "source=poll client_id={d}", .{self.clients.items[client_idx].client_id}) catch "";
736	                    startup_probe.traceEvent("server", "client_fd_event", msg);
737	                    self.drainClient(client_idx);
738	                } else {
739	                    self.drainPaneReadable(fd);
740	                }
741	            }
742	        }

